// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./RewardsVault.sol";

contract MiningSession {
    struct MinerInfo {
        uint256 shares;
        uint256 rewardsClaimed;
    }

    RewardsVault public vault;

    address public owner;

    uint256 public currentEpoch;
    uint256 public target;
    uint256 public rewardPerShare;
    uint256 public difficulty;

    mapping(address => MinerInfo) public miners;
    mapping(uint256 => mapping(address => mapping(uint256 => bool))) public usedNonce;

    event EpochStarted(uint256 epoch, uint256 target, uint256 rewardPerShare);
    event ShareSubmitted(address indexed miner, uint256 epoch, uint256 nonce, bytes32 hash);
    event RewardsClaimed(address indexed miner, uint256 amount);
    event ParamsUpdated(uint256 target, uint256 rewardPerShare);
    event DifficultyUpdated(uint256 difficulty, uint256 newTarget);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    constructor(
        address _vault,
        uint256 _initialDifficulty,
        uint256 _rewardPerShare
    ) {
        owner = msg.sender;
        vault = RewardsVault(_vault);

        difficulty = _initialDifficulty;
        target = type(uint256).max >> _initialDifficulty;

        rewardPerShare = _rewardPerShare;
        currentEpoch = 1;

        emit EpochStarted(currentEpoch, target, rewardPerShare);
    }

    // ---------------- ADMIN ----------------

    function setDifficulty(uint256 _difficulty) external onlyOwner {
        require(_difficulty > 0 && _difficulty < 64, "invalid difficulty");
        difficulty = _difficulty;
        target = type(uint256).max >> _difficulty;

        emit DifficultyUpdated(_difficulty, target);
    }

    function startNewEpoch(uint256 _rewardPerShare) external onlyOwner {
        currentEpoch += 1;
        rewardPerShare = _rewardPerShare;

        // target stays tied to difficulty
        target = type(uint256).max >> difficulty;

        emit EpochStarted(currentEpoch, target, rewardPerShare);
    }

    function updateParams(uint256 _rewardPerShare) external onlyOwner {
        rewardPerShare = _rewardPerShare;
        emit ParamsUpdated(target, _rewardPerShare);
    }

    // ---------------- MINING ----------------

    function submitShare(uint256 nonce) external {
        require(!usedNonce[currentEpoch][msg.sender][nonce], "Nonce used");

        bytes32 h = keccak256(abi.encodePacked(msg.sender, currentEpoch, nonce));
        require(uint256(h) < target, "Difficulty not met");

        usedNonce[currentEpoch][msg.sender][nonce] = true;

        MinerInfo storage miner = miners[msg.sender];
        miner.shares += 1;

        emit ShareSubmitted(msg.sender, currentEpoch, nonce, h);
    }

    // ---------------- REWARDS ----------------

    function pendingRewards(address minerAddr) public view returns (uint256) {
        MinerInfo memory m = miners[minerAddr];
        uint256 total = m.shares * rewardPerShare;
        return total - m.rewardsClaimed;
    }

    function claimRewards() external {
        uint256 amount = pendingRewards(msg.sender);
        require(amount > 0, "No rewards");

        miners[msg.sender].rewardsClaimed += amount;
        vault.distribute(msg.sender, amount);

        emit RewardsClaimed(msg.sender, amount);
    }

    function getShares(address miner) external view returns (uint256) {
        return miners[miner].shares;
    }

    // ---------------- FRONTEND SUPPORT ----------------

    function getWork(address miner)
        external
        view
        returns (
            uint256 epoch,
            uint256 difficultyOut,
            uint256 targetOut
        )
    {
        return (currentEpoch, difficulty, target);
    }

    function epochHash(address miner, uint256 nonce) external view returns (bytes32) {
        return keccak256(abi.encodePacked(miner, currentEpoch, nonce));
    }
}

contracts/MockToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract MockToken {
    string public name = "MockToken";
    string public symbol = "MOCK";
    uint8 public decimals = 18;
    uint256 public totalSupply;

    mapping(address => uint256) public balanceOf;

    constructor() {
        totalSupply = 1_000_000 ether;
        balanceOf[msg.sender] = totalSupply;
    }

    function transfer(address to, uint256 amount) external returns (bool) {
        require(balanceOf[msg.sender] >= amount, "Insufficient balance");
        balanceOf[msg.sender] -= amount;
        balanceOf[to] += amount;
        return true;
    }

    function transferFrom(address from, address to, uint256 amount) external returns (bool) {
        require(balanceOf[from] >= amount, "Insufficient balance");
        balanceOf[from] -= amount;
        balanceOf[to] += amount;
        return true;
    }
}

contracts/RewardsVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

interface IERC20 {
    function transfer(address to, uint256 amount) external returns (bool);
}

contract RewardsVault {
    address public owner;
    IERC20 public rewardToken;

    constructor(address _rewardToken) {
        owner = msg.sender;
        rewardToken = IERC20(_rewardToken);
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    // Send rewards to a miner
    function distribute(address miner, uint256 amount) external onlyOwner {
        require(rewardToken.transfer(miner, amount), "Transfer failed");
    }
}

contracts/RewardToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract RewardToken {
    string public name = "RewardToken";
    string public symbol = "RWT";
    uint8 public decimals = 18;

    uint256 public totalSupply;
    mapping(address => uint256) public balanceOf;
    mapping(address => mapping(address => uint256)) public allowance;

    address public owner;
    address public minter;

    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);
    event MinterUpdated(address indexed newMinter);

    modifier onlyOwner() {
        require(msg.sender == owner, "not owner");
        _;
    }

    modifier onlyMinter() {
        require(msg.sender == minter, "not minter");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    function setMinter(address _minter) external onlyOwner {
        minter = _minter;
        emit MinterUpdated(_minter);
    }

    function _transfer(address from, address to, uint256 value) internal {
        require(to != address(0), "zero addr");
        require(balanceOf[from] >= value, "balance");
        unchecked {
            balanceOf[from] -= value;
            balanceOf[to] += value;
        }
        emit Transfer(from, to, value);
    }

    function transfer(address to, uint256 value) external returns (bool) {
        _transfer(msg.sender, to, value);
        return true;
    }

    function approve(address spender, uint256 value) external returns (bool) {
        allowance[msg.sender][spender] = value;
        emit Approval(msg.sender, spender, value);
        return true;
    }

    function transferFrom(address from, address to, uint256 value) external returns (bool) {
        uint256 allowed = allowance[from][msg.sender];
        require(allowed >= value, "allowance");
        unchecked {
            allowance[from][msg.sender] = allowed - value;
        }
        _transfer(from, to, value);
        return true;
    }

    function mint(address to, uint256 value) external onlyMinter {
        require(to != address(0), "zero addr");
        totalSupply += value;
        balanceOf[to] += value;
        emit Transfer(address(0), to, value);
    }
}

contracts/WorkVerifier.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract WorkVerifier {
    mapping(bytes32 => bool) public usedWork;

    function verifyWork(bytes32 workHash, uint256 target) external returns (bool) {
        require(!usedWork[workHash], "Duplicate work");
        usedWork[workHash] = true;
        return uint256(workHash) < target;
    }
}

